type Query {
  item(id: ID!): Item @openfed__queryCache(maxAge: 300)
  itemByPid(pid: ID! @openfed__is(fields: "id")): Item @openfed__queryCache(maxAge: 300)
  items: [Item!]! @openfed__queryCache(maxAge: 300)
  itemsByIds(ids: [ID!]! @openfed__is(fields: "id")): [Item!]! @openfed__queryCache(maxAge: 300)
  product(id: ID!, region: String!): Product @openfed__queryCache(maxAge: 300)
  productBySku(sku: String!): Product @openfed__queryCache(maxAge: 300)
  productByName(name: String!): Product @openfed__queryCache(maxAge: 300)
  productByKey(key: ProductKeyInput! @openfed__is(fields: "id region")): Product @openfed__queryCache(maxAge: 300)
  warehouse(locationId: ID! @openfed__is(fields: "location.id")): Warehouse @openfed__queryCache(maxAge: 300)
  # warehouseByInput exercises the same nested @key as `warehouse` but reaches it
  # via an input object using GraphQL selection syntax in @openfed__is. This produces the
  # multi-hop argumentPath ["input","location","id"] instead of the scalar
