  # cache writes don't persist (cache lookup uses correct key but never hits).
  warehouseByInput(input: WarehouseLocationInput! @openfed__is(fields: "location { id }")): Warehouse @openfed__queryCache(maxAge: 300)
}

input ProductKeyInput {
  id: ID!
  region: String!
}

input WarehouseLocationInput {
  location: WarehouseLocationKeyInput!
}

input WarehouseLocationKeyInput {
  id: ID!
}

type Mutation {
  updateItem(id: ID!, name: String!): Item @openfed__cacheInvalidate
  deleteItem(id: ID!): Item @openfed__cacheInvalidate
  createItem(name: String!, category: String!): Item! @openfed__cachePopulate(maxAge: 60)
  # deleteProduct invalidates a composite-key entity (Product @key("id region")).
  # Used to pin behavior for cache invalidation when the entity uses a composite
  # @key — a separate code path from the simple id-only key in deleteItem.
  deleteProduct(id: ID!, region: String!): Product @openfed__cacheInvalidate
}

type Subscription {
  itemUpdated: Item @openfed__cacheInvalidate
  itemCreated: Item @openfed__cachePopulate
}

type Item @key(fields: "id") @openfed__entityCache(maxAge: 300) {
